  }

  /**
   * Creates a single-bound `<offset> preceding` frame extent.
   */
  preceding(offset: FrameOffsetExpression): FrameExtentBuilder<DB, TB> {
    return new FrameExtentBuilder(
      FrameNode.create(
        this.#unit,
        FrameBoundNode.createPreceding(parseFrameOffset(offset)),
      ),
    )
  }

  /**
   * Creates a single-bound `current row` frame extent.
   */
  currentRow(): FrameExtentBuilder<DB, TB> {
