        this.#unit,
        FrameBoundNode.createFollowing(parseFrameOffset(offset)),
      ),
    )
  }

  /**
   * Creates a single-bound `unbounded following` frame extent.
   */
  unboundedFollowing(): FrameExtentBuilder<DB, TB> {
    return new FrameExtentBuilder(
      FrameNode.create(this.#unit, FrameBoundNode.createUnboundedFollowing()),
    )
  }

  /**
   * Starts a `between unbounded preceding and ...` frame extent.
   */
  betweenUnboundedPreceding(): FrameBetweenBuilder<DB, TB> {
    return new FrameBetweenBuilder(
      this.#unit,
      FrameBoundNode.createUnboundedPreceding(),
    )
  }

  /**
   * Starts a `between <offset> preceding and ...` frame extent.
   */
  betweenPreceding(offset: FrameOffsetExpression): FrameBetweenBuilder<DB, TB> {
    return new FrameBetweenBuilder(
      this.#unit,
      FrameBoundNode.createPreceding(parseFrameOffset(offset)),
    )
  }

  /**
   * Starts a `between current row and ...` frame extent.
   */
  betweenCurrentRow(): FrameBetweenBuilder<DB, TB> {
    return new FrameBetweenBuilder(this.#unit, FrameBoundNode.createCurrentRow())
  }

  /**
   * Starts a `between <offset> following and ...` frame extent.
