export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(
    node: OverNode,
    queryId?: QueryId,
  ): OverNode {
    const transformed = super.transformOver(node, queryId)

    if (
      !transformed.frame ||
      !this.#isRedundantFrame(transformed.frame, !!transformed.orderBy)
    ) {
      return transformed
    }

    const { frame, ...rest } = transformed

    return freeze(rest) as OverNode
  }

  #isRedundantFrame(frame: FrameNode, hasOrderBy: boolean): boolean {
    if (frame.unit !== 'range') {
      return false
    }

    if (frame.exclusion) {
      return false
    }

    if (!frame.end) {
      return false
    }

    if (!this.#isUnboundedPreceding(frame.start)) {
      return false
    }

    return hasOrderBy
      ? this.#isCurrentRow(frame.end)
      : this.#isUnboundedFollowing(frame.end)
  }

