    return bound.type === 'preceding' && !!bound.unbounded
  }

  #isCurrentRow(bound: FrameBoundNode): boolean {
    return bound.type === 'currentRow'
  }

  #isUnboundedFollowing(bound: FrameBoundNode): boolean {
    return bound.type === 'following' && !!bound.unbounded
  }
